"use strict";(self.webpackChunktemporal_documentation=self.webpackChunktemporal_documentation||[]).push([["88294"],{91340(e){e.exports=JSON.parse('{"tag":{"label":"Reference","permalink":"/tags/reference","allTagsPath":"/tags","count":14,"items":[{"id":"references/errors","title":"Errors","description":"This reference outlines possible Workflow Task errors, causes, and resolution steps in Temporal. It covers various error scenarios such as attribute failures, size limits, and system resource issues.","permalink":"/references/errors"},{"id":"glossary","title":"Glossary","description":"The following terms have specific definitions within the context of the Temporal Platform.","permalink":"/glossary"},{"id":"references/cluster-metrics","title":"OSS Temporal Service metrics reference","description":"A Temporal Service emits metrics helping operators monitor performance and set alerts. Metrics like service requests, latencies, and errors are tracked. Use metric_defs.go for more.","permalink":"/references/cluster-metrics"},{"id":"references/configuration","title":"Temporal Cluster configuration reference","description":"Configure a Temporal Cluster using the development.yaml file to set global parameters, metrics, security, persistence, and service roles, ensuring a streamlined setup and management process.","permalink":"/references/configuration"},{"id":"references/dynamic-configuration","title":"Temporal Cluster dynamic configuration reference","description":"Temporal Cluster offers dynamic configuration keys that you can update on the fly to optimize performance without service interruption. Customize these settings to meet specific Workflow, Activity, Namespace, or Task Queue requirements, and test thoroughly before deploying to production. For more details, visit the Temporal GitHub repository.","permalink":"/references/dynamic-configuration"},{"id":"references/commands","title":"Temporal Commands reference","description":"Discover the range of Commands Workers can issue to the Temporal Service after Workflow Task Execution, from Completing Workflow Execution to Start Timer and Signal External Workflow Execution.","permalink":"/references/commands"},{"id":"references/events","title":"Temporal Events reference","description":"Events in a Temporal Service respond to external occurrences and Workflow Commands. Workflow Execution Event History includes WorkflowExecutionStarted, WorkflowExecutionCompleted, WorkflowExecutionFailed, and many more.","permalink":"/references/events"},{"id":"references/failures","title":"Temporal Failures reference","description":"A Failure in Temporal represents different types of errors in the system, categorized and managed uniquely within SDKs and protobuf messages, impacting Workflow and Activity operations.","permalink":"/references/failures"},{"id":"references/index","title":"Temporal Platform references","description":"Explore comprehensive references for SDK Metrics, Commands, Events, Web UI environment variables, Temporal Service and Web UI configurations, and API guides for Go, Java, Python, TypeScript, .NET, and PHP.","permalink":"/references/"},{"id":"references/sdk-metrics","title":"Temporal SDK metrics reference","description":"Temporal SDKs emit metrics covering Client usage and Worker Processes. Metrics can be tuned to improve Worker performance and are prefixed with temporal_ before export.","permalink":"/references/sdk-metrics"},{"id":"references/server-options","title":"Temporal Server options reference","description":"Run the Temporal Server as a Go application by incorporating the package go.temporal.io/server/temporal. Customize server options like Config, Authorization, and TLS.","permalink":"/references/server-options"},{"id":"references/web-ui-configuration","title":"Temporal Web UI configuration reference","description":"Manage your Temporal Server efficiently with development.yaml. Set parameters for Auth, TLS, ports, and more.","permalink":"/references/web-ui-configuration"},{"id":"references/web-ui-environment-variables","title":"Temporal Web UI environment variables reference","description":"Dynamically configure Temporal Web UI with environment variables in Docker for settings like TEMPORAL_ADDRESS, authentication, TLS, OpenAPI, and more.","permalink":"/references/web-ui-environment-variables"},{"id":"develop/worker-tuning-reference","title":"Worker tuning quick reference","description":"A quick reference guide for Temporal Worker configuration defaults across SDKs, organized by resource type (compute, memory, IO) with key metrics for each.","permalink":"/develop/worker-tuning-reference"}],"unlisted":false}}')}}]);